code = """import json
import re

# Read the full business data results
business_file = locals().get('var_functions.query_db:26', '')
business_data = []

if isinstance(business_file, str) and business_file.endswith('.json'):
    with open(business_file, 'r') as f:
        business_data = json.load(f)
else:
    business_data = locals().get('var_functions.query_db:26', [])

# Get reviews data
reviews_result = locals().get('var_functions.query_db:8', [])

# Build lookup for businesses
business_lookup = {}
for doc in business_data:
    business_id = doc.get('business_id', '')
    if business_id.startswith('businessid_'):
        business_ref = business_id.replace('businessid_', 'businessref_')
        business_lookup[business_ref] = {
            'name': doc.get('name', ''),
            'description': doc.get('description', '')
        }

# Extract categories from descriptions using regex
def extract_categories(description):
    if not description:
        return []
    
    categories = []
    
    # Pattern 1: "services in Category1, Category2, Category3"
    pattern1 = r'services in ([^\.]+)'
    match1 = re.search(pattern1, description, re.IGNORECASE)
    if match1:
        text = match1.group(1)
        # Split by comma and clean
        for cat in text.split(','):
            clean_cat = cat.strip().rstrip('.').strip()
            if clean_cat and len(clean_cat) > 2:
                categories.append(clean_cat)
    
    # Pattern 2: "including Category1, Category2, Category3"
    pattern2 = r'including ([^\.]+)'
    match2 = re.search(pattern2, description, re.IGNORECASE)
    if match2:
        text = match2.group(1)
        # Handle "and" before the last item
        if ' and ' in text:
            parts = text.split(' and ')
            # Process first part (comma-separated)
            if len(parts) > 0:
                first_cats = [c.strip().rstrip('.').strip() for c in parts[0].split(',')]
                categories.extend([c for c in first_cats if c and len(c) > 2])
            # Add last item
            if len(parts) > 1:
                last_cat = parts[1].strip().rstrip('.').strip()
                if last_cat and len(last_cat) > 2:
                    categories.append(last_cat)
        else:
            # No "and", just split by commas
            cats = [c.strip().rstrip('.').strip() for c in text.split(',')]
            categories.extend([c for c in cats if c and len(c) > 2])
    
    return categories

# Get review counts per business
total_reviews_by_business = {}
for review in reviews_result:
    business_ref = review.get('business_ref', '')
    count = int(review.get('review_count', '0'))
    total_reviews_by_business[business_ref] = count

# Aggregate review counts by category
category_totals = {}
for business_ref, review_count in total_reviews_by_business.items():
    if business_ref in business_lookup:
        description = business_lookup[business_ref]['description']
        categories = extract_categories(description)
        for cat in categories:
            category_totals[cat] = category_totals.get(cat, 0) + review_count

# Sort and get top 5
top_5_categories = sorted(category_totals.items(), key=lambda x: x[1], reverse=True)[:5]

result = {
    'total_businesses_loaded': len(business_data),
    'businesses_with_reviews': len(total_reviews_by_business),
    'total_categories_found': len(category_totals),
    'top_5_categories': top_5_categories
}

print('__RESULT__:')
print(json.dumps(result))"""

